# Weekly friction aggregator: cluster signals into a ranked register
from collections import defaultdict
from dataclasses import dataclass, field
from typing import List

SEVERITY_WEIGHTS = {
    "CI":       2.5,   # hours per occurrence
    "scaffold": 1.0,
    "deploy":   3.0,
    "portal":   0.5,
    "SDK":      1.5,
}


@dataclass
class FrictionItem:
    component: str
    description: str
    signal_ids: List[str] = field(default_factory=list)
    incident_count: int = 0
    unique_teams: set = field(default_factory=set)

    @property
    def friction_score(self) -> float:
        severity = SEVERITY_WEIGHTS.get(self.component, 1.0)
        return self.incident_count * severity * len(self.unique_teams)


def aggregate_signals(signals: list) -> List[FrictionItem]:
    """Cluster signals by component and keyword bucket."""
    clusters: dict[str, FrictionItem] = defaultdict(
        lambda: FrictionItem(component="", description="")
    )
    for s in signals:
        key = f"{s['component']}::{s['cluster_label']}"
        item = clusters[key]
        item.component = s["component"]
        item.description = s["cluster_label"]
        item.signal_ids.append(s["id"])
        item.incident_count += 1
        item.unique_teams.add(s["team"])

    return sorted(clusters.values(), key=lambda x: x.friction_score, reverse=True)
